import { model, Model, Schema, Document } from 'mongoose';

// Create a Mongoose schema for the people collection
const PeopleSchema: Schema = new Schema({
  firstName: { type: String, required: true },
  lastName: { type: String, required: true }
});

// Create a Mongoose model for the people collection
export const People: Model<Document> = model('people', PeopleSchema);

async function searchPeople(name: string) {
  // Handle empty input
  if (!name) {
    return [];
  }

  // Split the input into parts
  const parts = name.split(' ');
  const firstName = parts[0];
  const lastName = parts.slice(1).join(' ');

  // Search for matches in the people collection
  const query = {
    $or: [
      { firstName: { $regex: firstName, $options: 'i' } },
      { lastName: { $regex: lastName, $options: 'i' } }
    ]
  };

  const people = await People.find(query);

  return people;
}
```

This function:

1. Splits the input string into parts to determine if it's a full name, first name, or last name.
2. Uses Mongoose's `$or` operator to search for matches based on either the first name or last name.
3. Uses case-insensitive regular expressions with the `$options: 'i'` flag to match the input string case-insensitively.
4. Returns an array of matching documents.

You can use it like this:

```typescript
const name = 'John Doe';
const results = await searchPeople(name);
console.log(results);
```

This will search the `people` collection for documents where either the `firstName` matches "John" (case-insensitive) OR the `lastName` matches "Doe" (case-insensitive).

